        // nums[0] == nums[1], cost to make nums[0] > nums[1] is 1.
        // Cost to make nums[1] > nums[0] is 1. Minimum is 1.
        return 1;
    }

    // For n >= 3, it is always possible to achieve n peaks by making all elements
    // arbitrarily large (e.g., [M, 1, M, 1, M, ...]), but since we only add 1, 
    // we need to see if there's a structural limit.
    // If we make every element large enough, they all become peaks.
    // E.g., set all nums[i] = MAX + C. Then nums[i] > neighbors always.
    // Since the cost is additive, we can always make n peaks.
    // The only impossible case mentioned in the prompt example is n=3, [3, 7, 3], k=2 -> -1.
    // Let's check why [3, 7, 3] cannot have 2 peaks.
    // Peaks can occur at i, i+1, i+2, ...
    // If i is a peak: nums[i] > nums[i-1] AND nums[i] > nums[i+1]
    // If i+1 is a peak: nums[i+1] > nums[i] AND nums[i+1] > nums[i+2]
    // If both i and i+1 are peaks:
    // 1. nums[i] > nums[i+1]
    // 2. nums[i+1] > nums[i]
    // This is a contradiction (strict inequality). Thus, adjacent elements cannot both be peaks.
    // The maximum number of peaks is ceil(n/2).

    const max_peaks = Math.ceil(n / 2);
    if (k > max_peaks) {
        return -1;
    }

    // The problem now is to select k indices to be peaks with minimum cost.
    // Since peaks cannot be adjacent, we must select k indices such that no two are adjacent (circularly).
    // This is equivalent to selecting k non-adjacent items from n items in a circle.

    // This problem smells like Dynamic Programming, specifically finding the minimum cost 
    // to satisfy constraints on a circle, which is often solved by breaking the circle.

    // Let's re-examine the cost. To make index i a peak, we need:
    // nums[i] > nums[prev] AND nums[i] > nums[next].
    // Let's assume we fix the set of k indices $P$ that will be peaks.
    // For $i \in P$, let $p=prev(i)$ and $n=next(i)$.
    // We need $nums'[i] > nums'[p]$ and $nums'[i] > nums'[n]$.
    // The total cost is $\sum (nums'[i] - nums[i])$.

    // This formulation is complex because making $nums[i]$ large affects the requirements for $p$ and $n$.
    // However, the cost only increases $nums[i]$. If we only increase peaks, the neighbors' requirements might change.

    // Crucial realization: If we only increase the elements we *want* to be peaks, 
    // the cost is minimized if we only increase the peak element $nums[i]$ 
    // just enough to overcome the current (or modified) values of its neighbors.

    // If we decide on a set of k non-adjacent indices $P$ to be peaks, 
    // we want to minimize $\sum_{i \in P} \text{cost}(i)$.

    // Cost for peak $i$:
    // Target value $T_i = \max(\text{neighbor\_prev}, \text{neighbor\_next}) + 1$.
    // Cost = $\max(0, T_i - nums[i])$.

    // If we only increase $nums[i]$ for $i \in P$, the neighbors $p$ and $n$ are *not* increased.
    // So, the cost for $i \in P$ is fixed based on the original array values of $p$ and $n$.
    // Cost for $i$: $\max(0, \max(nums[p], nums[n]) + 1 - nums[i])$.

    // Since we are only increasing peaks, the neighbors' values remain fixed at their original values.
    // Therefore, the cost for a chosen set $P$ is simply the sum of individual costs, and the choices are independent!

    // The problem simplifies to:
    // 1. Identify all possible peak locations $i$ (where $i$ and its neighbors are not peaks).
    // 2. Calculate the minimum cost $C_i$ to make $i$ a peak, assuming neighbors are unchanged.
    // 3. Select $k$ non-adjacent indices $i$ with the smallest $C_i$.

    // Calculate costs $C_i$ for all $i$ that could potentially be peaks.
    const costs = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        const prev_idx = (i - 1 + n) % n;
        const next_idx = (i + 1) % n;

        const val_prev = nums[prev_idx];
        const val_next = nums[next_idx];

        const required_val = Math.max(val_prev, val_next) + 1;
        const cost = Math.max(0, required_val - nums[i]);
        costs[i] = cost;
    }

    // Now we need to select k non-adjacent indices $i$ that minimize $\sum C_i$.
    // This is the Maximum Weight Independent Set (MWIS) on a Cycle Graph, but we want to select *exactly* k items.
    // This is the $k$-Minimum Weight Independent Set on a Cycle Graph.

    // We break the cycle at an arbitrary point (say, between index n-1 and 0) and use DP.
    // Since the selection must be independent, we cannot select both 0 and n-1.

    // DP approach for a path (linear arrangement):
    // Let DP[i][j][state] be the minimum cost using elements up to index i, selecting exactly j peaks, 
    // where state indicates whether element i was selected (1) or not (0).
    // State 1: nums[i] is a peak.
    // State 0: nums[i] is not a peak.

    // Size of DP table: (n) x (k+1) x 2

    // Initialization:
    // DP[i][j][state] = Infinity

    // Base Case i = 0:
    // DP[0][1][1] = costs[0] (Select 0)
    // DP[0][0][0] = 0 (Don't select 0)

    // Transition (for i = 1 to n-1):
    for (let i = 1; i < n; i++) {
        // Case: i is NOT selected (state 0)
        // We can come from i-1 selected or i-1 not selected.
        for (let j = 0; j <= k; j++) {
            DP[i][j][0] = Math.min(
                DP[i-1][j][0], // i-1 not selected
                DP[i-1][j][1]  // i-1 selected
            );
        }

        // Case: i IS selected (state 1)
        // We must come from i-1 NOT selected. j must be at least 1.
        for (let j = 1; j <= k; j++) {
            DP[i][j][1] = DP[i-1][j-1][0] + costs[i];
        }
    }

    // Final answer for the path [0, n-1]:
    // Min cost = min(DP[n-1][k][0], DP[n-1][k][1])

    // Since it's a cycle, we must handle the adjacency of 0 and n-1.
    let min_cost = Infinity;

    // Scenario 1: Index 0 is NOT selected (State 0 for index 0)
    // We run the linear DP on indices [1, n-1] with target k, ensuring 0 is excluded.
    // This is equivalent to running the DP on [1, n-1] with k peaks, where we force DP[0][*][0] = 0.

    // To simplify, we iterate over the decision for index 0:

    // A) Assume index 0 is NOT chosen (Cost for index 0 is 0, we need k peaks in [1, n-1])
    // We run DP for [1, n-1] with k peaks.

    // Redefining DP for path [1, n-1]
    const DP_A = Array(n).fill(0).map(() => Array(k + 1).fill(Infinity).map(() => [Infinity, Infinity]));

    // Base Case i = 1
    DP_A[1][0][0] = 0; // Don't select 1
    DP_A[1][1][1] = costs[1]; // Select 1

    for (let i = 2; i < n; i++) {
        // State 0: i is NOT selected
        for (let j = 0; j <= k; j++) {
            DP_A[i][j][0] = Math.min(
                DP_A[i-1][j][0],
                DP_A[i-1][j][1]
            );
        }

        // State 1: i IS selected
        for (let j = 1; j <= k; j++) {
            DP_A[i][j][1] = DP_A[i-1][j-1][0] + costs[i];
        }
    }

    // Result for A: k peaks in [1, n-1]. Since 0 is excluded, there is no conflict with n-1.
    let cost_A = Math.min(DP_A[n-1][k][0], DP_A[n-1][k][1]);
    min_cost = Math.min(min_cost, cost_A);


    // B) Assume index 0 IS chosen (Cost is costs[0], we need k-1 peaks in [2, n-1], AND n-1 must NOT be chosen)
    if (k >= 1) {
        const required_k_B = k - 1;
        if (required_k_B >= 0) {
            // Run DP for path [2, n-1] with required_k_B peaks, forcing state 0 at n-1.

            // DP_B[i][j][state] for indices i = 2 to n-1
            const DP_B = Array(n).fill(0).map(() => Array(k + 1).fill(Infinity).map(() => [Infinity, Infinity]));

            // Base Case i = 2
            DP_B[2][0][0] = 0; // Don't select 2
            DP_B[2][1][1] = costs[2]; // Select 2

            for (let i = 3; i < n; i++) {
                // State 0: i is NOT selected
                for (let j = 0; j <= k; j++) {
                    DP_B[i][j][0] = Math.min(
                        DP_B[i-1][j][0],
                        DP_B[i-1][j][1]
                    );
                }

                // State 1: i IS selected
                for (let j = 1; j <= k; j++) {
                    DP_B[i][j][1] = DP_B[i-1][j-1][0] + costs[i];
                }
            }

            // Final result for B: We must ensure n-1 is NOT selected (state 0).
            let cost_B_path = DP_B[n-1][required_k_B][0];

            if (cost_B_path !== Infinity) {
                 // Add the cost of selecting index 0
                min_cost = Math.min(min_cost, cost_B_path + costs[0]);
            }
        }
    }

    // If min_cost is still Infinity, it's impossible (shouldn't happen if k <= max_peaks, but for safety)
    return min_cost === Infinity ? -1 : min_cost;
}

